export default function hideModals() {
  const popupTable = document.querySelector(".hot-products-popup-table");
  const productTable = document.querySelector(
    ".hot-products__table-wrapper--products"
  );
  const categoriesTable = document.querySelector(
    ".hot-products__table-wrapper--categories"
  );
  const overlay = document.querySelector(".overlay");
  const popupSelectedInfo = document.querySelector(
    ".hot-products__popup-selected-info--products"
  );
  const noResultsMessage = categoriesTable?.querySelector(
    ".hot-products__no-results"
  );
  const productsTable = document.querySelector(
    ".hot-products__table-wrapper--added-products"
  );

  productsTable.classList.add("hot-products__table-wrapper--hidden");
  popupTable.classList.remove("hot-products-popup-table--active");
  productTable.classList.add("hot-products__table-wrapper--hidden");
  categoriesTable.classList.remove("hot-products__table-wrapper--hidden");
  overlay.classList.remove("overlay--active");
  popupSelectedInfo.classList.remove(
    "hot-products__popup-selected-info--visible"
  );

  if (noResultsMessage) {
    noResultsMessage.remove();
  }
}
