export default function showLimitErrorPopup(errorMessage) {
  const existingPopup = document.querySelector(
    ".hot-products-limit-error-popup"
  );
  if (existingPopup) {
    existingPopup.remove();
  }

  const overlay = document.createElement("div");
  overlay.className = "hot-products-limit-error-overlay";

  const popup = document.createElement("div");
  popup.className = "hot-products-limit-error-popup";
  const apiErrorText = document.querySelector(".hot-products-wrapper").dataset
    .apiErrorTitle;

  popup.innerHTML = `
    <div class="hot-products-limit-error-popup__content">
      <button class="hot-products-limit-error-popup__close" type="button">
        <svg width="16" height="16" viewBox="0 0 16 16" fill="none">
          <path d="M12 4L4 12M4 4L12 12" stroke="currentColor" stroke-width="2" stroke-linecap="round"/>
        </svg>
      </button>
      <p class="hot-products-limit-error-popup__text">
        ${apiErrorText}
      </p>
      <p class="hot-products-limit-error-popup__text hot-products-limit-error-popup__text--black">
        ${errorMessage}
      </p>
    </div>
  `;

  const closeButton = popup.querySelector(
    ".hot-products-limit-error-popup__close"
  );

  const closePopup = () => {
    overlay.remove();
  };

  closeButton.addEventListener("click", closePopup);
  overlay.addEventListener("click", (e) => {
    if (e.target === overlay) {
      closePopup();
    }
  });

  document.addEventListener("keydown", function handleEscape(e) {
    if (e.key === "Escape") {
      closePopup();
      document.removeEventListener("keydown", handleEscape);
    }
  });

  overlay.appendChild(popup);
  document.body.appendChild(overlay);
}
