export default function showSuccessAlert(text) {
  const hotProductsWrapper = document.querySelector(".hot-products-wrapper");

  if (!hotProductsWrapper) return;

  const existingAlerts = document.querySelectorAll(
    ".hot-products-success-alert"
  );

  if (existingAlerts.length > 0) {
    existingAlerts.forEach((alert) => {
      alert.remove();
    });
  }

  const template = `    
        <div class="hot-products-success-alert__content">
            <h3 class="hot-products-success-alert__title">${hotProductsWrapper.dataset.apiSuccessTitle}</h3>
            <p class="hot-products-success-alert__text">${text}</p>
        </div>`;

  const alert = document.createElement("div");
  alert.classList =
    "hot-products-success-alert hot-products-success-alert--active";
  alert.innerHTML = template;

  hotProductsWrapper.appendChild(alert);

  setTimeout(() => {
    alert.classList.remove("hot-products-success-alert--active");
  }, 5000);
}
