import loadPeriodPicker from "./loadPeriodPicker";
import loadHotProducts from "./loadHotProducts";

export default function loadAddedProducts(response) {
  hideProductsTable();
  showAddedProductsTable();

  const addedTableBody = document.querySelector(
    ".hot-products__table--added-products tbody"
  );

  const rejectedTableBody = document.querySelector(
    ".hot-products__table--rejected-products tbody"
  );

  const rejectedProductsInfo = document.querySelector(
    ".hot-products__rejected-products-info"
  );

  if (!response || !addedTableBody || !rejectedTableBody) {
    displayNoResults(addedTableBody);
    rejectedProductsInfo.style.display = "none";
    rejectedTableBody.innerHTML = "";
    return;
  }

  const { added, rejected } = response;
  const pluginUrl = document.querySelector(".hot-products-wrapper").dataset
    .pluginUrl;
  const highlightPeriodText = document.querySelector(".hot-products-wrapper")
    .dataset.highlightPeriodNotSelected;

  if (added && added.products && added.products.length > 0) {
    addedTableBody.innerHTML = added.products
      .map(
        (product, index) => `
      <tr data-product-id="${product.id}">
        <td class="hot-products__td hot-products__td--count hot-products__td--count-row">
            <div class="hot-products__count-wrapper">
                <img src="${pluginUrl}../../../assets/img/hp-added.svg" alt="">
                <span>${index + 1}.</span>
            </div>
        </td>
        <td class="hot-products__td hot-products__td--added-product-name">
            ${product.name}
        </td>
        <td class="hot-products__td hot-products__td--id">${product.id}</td>
        <td class="hot-products__td hot-products__td--highlight-period">
          <div class="hot-products__period" data-start-date="${
            product.start_date
          }" data-end-date="${product.end_date}">
              <img src="${pluginUrl}../../../assets/img/period.svg" alt="">
              <input class="hot-products__period-input--added" type="text" placeholder="${highlightPeriodText}" readonly="readonly">
          </div>
        </td>
      </tr>
    `
      )
      .join("");

    loadPeriodPicker({
      element: ".hot-products__period-input--added",
      afterAvailabilityUpdate: () => {
        loadHotProducts();
      },
    });
  } else {
    displayNoResults(addedTableBody);
  }

  if (rejected && rejected.products && rejected.products.length > 0) {
    rejectedProductsInfo.style.display = "block";
    rejectedTableBody.innerHTML = rejected.products
      .map(
        (product, index) => `
      <tr data-product-id="${product.id}">
        <td class="hot-products__td hot-products__td--count hot-products__td--count-row">
            <div class="hot-products__count-wrapper">
                <img src="${pluginUrl}../../../assets/img/hp-rejected.svg" alt="">
                <span>${index + 1}.</span>
            </div>
        </td>
        <td class="hot-products__td hot-products__td--added-product-name">
            <span>${product.name}</span>
        </td>
        <td class="hot-products__td hot-products__td--added-product-id">${
          product.id
        }</td>
      </tr>
    `
      )
      .join("");
  } else {
    displayNoResults(rejectedTableBody);
  }
}

function hideProductsTable() {
  const productsTable = document.querySelector(
    ".hot-products__table-wrapper--products"
  );
  productsTable.classList.add("hot-products__table-wrapper--hidden");
}

function showAddedProductsTable() {
  const productsTable = document.querySelector(
    ".hot-products__table-wrapper--added-products"
  );
  productsTable.classList.remove("hot-products__table-wrapper--hidden");
}

function displayNoResults(tableBody) {
  const noResultsMessage = document.querySelector(".hot-products-wrapper")
    .dataset.noResultsMessage;

  tableBody.innerHTML = `
    <tr>
      <td colspan="4" style="text-align: center;">
        ${noResultsMessage}
      </td>
    </tr>
  `;
}
